input.old_string:
const getStatusColor = (status: Payout["status"]) => {
  switch (status) {
    case "ready":
      return "bg-teal-100 text-foreground";
    case "sent":
      return "bg-teal-100 text-foreground";
    case "rejected":
      return "bg-red-100 text-foreground";
    default:
      return "bg-slate-200 text-foreground";
  }
};

