input.old_string:
const getDetailColor = (context?: EntrySourceType | FundAllocationAction) => {
  if (!context) return "bg-slate-200";
  switch (context) {
    case "void":
      return "bg-slate-200";
    case "refund":
    case "ach_return":
    case "ach_return_fee":
    case "partial_refund":
      return "bg-yellow-100";
    case "transaction":
      return "bg-teal-100";
    case "chargeback":
    case "chargeback_fee":
    case "chargeback_reversal":
      return "bg-red-100";
    default:
      return "bg-slate-200";
  }
};

input.new_string:
const getDetailColor = (context?: EntrySourceType | FundAllocationAction) => {
  if (!context) return "bg-muted";
  switch (context) {
    case "void":
      return "bg-muted";
    case "refund":
    case "ach_return":
    case "ach_return_fee":
    case "partial_refund":
      return "bg-warning/25";
    case "transaction":
      return "bg-chart-2/20";
    case "chargeback":
    case "chargeback_fee":
    case "chargeback_reversal":
      return "bg-destructive/15";
    default:
      return "bg-muted";
  }
};
